   494→                if (ret != 0)
   495→                {
   496→                    return ret;
   497→                }
   498→            }
   499→        }
   500→        else
   501→        {
   502→            int ret = json2field(&(itr->value), msg, field, err);
   503→            if (ret != 0)
   504→            {
   505→                return ret;
